+        os.write(fd, b"-fd")
+        os.fsync(fd)
+        os.lseek(fd, 0, os.SEEK_SET)
+        read_after_write = os.read(fd, 64).decode("ascii")
+        fstat_after_write = stable_fd_stat(fd)
+    finally:
+        os.close(fd)
+
+    return {
